    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const content = ev.target?.result as string;
        setText(content);
        onProcess(content);
      };
      reader.readAsText(file);
    }
  }, [onProcess]);

  const handleProcess = () => {
    if (text.trim()) onProcess(text);
