export const mapEdiToForm856 = (doc: EdiDocument): Partial<FormData856> => {
    const flat = flattenSegments(doc.segments);
    const data: Partial<FormData856> = {
        lines: []
    };

    const bsn = flat.find(s => s.tag === 'BSN');
    if(bsn) {
        data.shipmentId = bsn.elements[1]?.value;
        data.shipDate = formatDate(bsn.elements[2]?.value);
        data.shipTime = bsn.elements[3]?.value;
    }

    const td5 = flat.find(s => s.tag === 'TD5');
    if(td5) data.carrierCode = td5.elements[2]?.value;

    const refCn = flat.find(s => s.tag === 'REF' && (s.elements[0]?.value === 'CN' || s.elements[0]?.value === 'BM'));
    if(refCn) data.trackingNumber = refCn.elements[1]?.value;

    flat.forEach((s, idx) => {
        if (s.tag === 'N1') {
            const id = s.elements[0]?.value;
            if (id === 'SF' || id === 'SE') {
                data.sellerName = s.elements[1]?.value;
                data.sellerId = s.elements[3]?.value;
            } else if (id === 'ST') {
                data.shipToName = s.elements[1]?.value;
                const n3 = flat[idx+1]?.tag === 'N3' ? flat[idx+1] : null;
                const n4 = flat[idx+2]?.tag === 'N4' ? flat[idx+2] : null;
                if(n3) data.shipToAddress = n3.elements[0]?.value;
                if(n4) {
                    data.shipToCity = n4.elements[0]?.value;
                    data.shipToState = n4.elements[1]?.value;
                    data.shipToZip = n4.elements[2]?.value;
                }
            }
        }
    });

    let currentPO = '';
    flat.forEach((s, idx) => {
        if(s.tag === 'PRF') {
            currentPO = s.elements[0]?.value;
        }
        if(s.tag === 'LIN') {
            const lineNo = s.elements[0]?.value;
            let partNumber = '';
            for(let i=1; i<s.elements.length; i+=2) {
                if(s.elements[i]?.value === 'VP' || s.elements[i]?.value === 'BP') {
                    partNumber = s.elements[i+1]?.value;
                    break;
                }
            }

            const sn1 = flat[idx+1]?.tag === 'SN1' ? flat[idx+1] : null;
            const qty = sn1 ? sn1.elements[1]?.value : '0';
            const uom = sn1 ? sn1.elements[2]?.value : 'EA';

            data.lines?.push({
                lineNo: lineNo || '',
                poNumber: currentPO,
                partNumber,
                qty,
                uom
            });
        }
    });

    return data;
};

import { EdiDocument, EdiSegment } from '../types';
import { flattenTree } from './ediParser';

export interface EdiRecord {
    id: string;         // The unique ID of the triggering segment (e.g., CLM segment ID)
    label: string;      // Human readable label (e.g., "Claim #12345")
    value: string;      // Secondary info (e.g., "$150.00")
    type: 'Claim' | 'Subscriber' | 'Member' | 'Transaction' | 'Payment' | 'Unknown';
    startIndex: number; // Index in the flattened segment list
}

export const extractRecords = (doc: EdiDocument): EdiRecord[] => {
    if (!doc) return [];

    const flat = flattenTree(doc.segments);
    const records: EdiRecord[] = [];
    const type = doc.transactionType;

    // --- 837 Claims ---
    if (type === '837') {
        flat.forEach((seg, index) => {
            if (seg.tag === 'CLM') {
                const claimId = seg.elements[0]?.value || 'Unknown';
                const amount = seg.elements[1]?.value || '0';
                records.push({
                    id: seg.id,
                    label: `Claim ${claimId}`,
                    value: `$${amount}`,
                    type: 'Claim',
                    startIndex: index
                });
            }
        });
    }
    // --- 834 Members ---
    else if (type === '834') {
        let currentSubscriberName = "";
        flat.forEach((seg, index) => {
            if (seg.tag === 'INS') {
                const isSub = seg.elements[0]?.value === 'Y';
                let name = "";

                // Scan forward for name
                for (let i = index + 1; i < flat.length; i++) {
                    const next = flat[i];
                    if (next.tag === 'INS' || next.tag === 'SE') break;
                    if (next.tag === 'NM1' && next.elements[0]?.value === 'IL') {
                        const first = next.elements[3]?.value || '';
                        const last = next.elements[2]?.value || '';
                        name = `${first} ${last}`.trim();
                        break;
                    }
                }

                if (isSub) {
                    currentSubscriberName = name;
                }

                records.push({
                    id: seg.id,
                    label: name || (isSub ? 'Subscriber' : 'Dependent'),
                    value: isSub ? 'Primary Subscriber' : `Dependent of ${currentSubscriberName || 'Subscriber'}`,
                    type: isSub ? 'Subscriber' : 'Member',
                    startIndex: index
                });
            }
        });
    }
    // --- 270/271 Eligibility ---
    else if (type === '270' || type === '271') {
        flat.forEach((seg, index) => {
            if (seg.tag === 'HL') {
                const level = seg.elements[2]?.value; 
                if (level === '22' || level === '23') {
                    const isDep = level === '23';
                    let name = isDep ? "Dependent" : "Subscriber";
                    let idInfo = "";

                    for (let i = index + 1; i < flat.length; i++) {
                        const next = flat[i];
                        if (next.tag === 'HL' || next.tag === 'SE') break;

                        if (next.tag === 'NM1' && (next.elements[0]?.value === 'IL' || next.elements[0]?.value === '03')) {
                             const first = next.elements[3]?.value || '';
                             const last = next.elements[2]?.value || '';
                             const id = next.elements[8]?.value;
                             name = `${first} ${last}`.trim();
                             if (id) idInfo = id;
                             break;
                        }
                    }

                    records.push({
                        id: seg.id,
                        label: name || (isDep ? "Dependent" : "Subscriber"),
                        value: idInfo,
                        type: isDep ? 'Member' : 'Subscriber',
                        startIndex: index
                    });
                }
            }
        });
    }
    // --- 276/277 Status ---
    else if (type === '276' || type === '277') {
        flat.forEach((seg, index) => {
            if (seg.tag === 'TRN' && (seg.elements[0]?.value === '1' || seg.elements[0]?.value === '2')) {
                const trace = seg.elements[1]?.value || 'Unknown';
                let amount = "";
                for (let i = index + 1; i < index + 5 && i < flat.length; i++) {
                     if (flat[i].tag === 'AMT') {
                         amount = `$${flat[i].elements[1]?.value}`;
                     }
                }
                records.push({
                    id: seg.id,
                    label: `Trace ${trace}`,
                    value: amount,
                    type: 'Claim',
                    startIndex: index
                });
            }
        });
    }
    // --- 835 Remittance ---
    else if (type === '835') {
        flat.forEach((seg, index) => {
            if (seg.tag === 'CLP') {
                const claimId = seg.elements[0]?.value || 'Unknown';
                const status = seg.elements[1]?.value;
                const paidAmt = seg.elements[2]?.value || '0';

                let statusLabel = 'Processed';
                if (status === '3' || status === '4') statusLabel = 'Denied';
                else if (status === '22') statusLabel = 'Reversal';

                records.push({
                    id: seg.id,
                    label: `Claim ${claimId}`,
                    value: `Paid $${paidAmt} (${statusLabel})`,
                    type: 'Payment',
                    startIndex: index
                });
            }
        });
    }

    if (records.length === 0 && flat.length > 2) {
        records.push({
            id: flat[0].id,
            label: 'Single Transaction',
            value: type,
            type: 'Transaction',
            startIndex: 0
        });
    }

    return records;
};

import { EdiDocument, EdiSegment } from '../types';

const uuid = () => Math.random().toString(36).substr(2, 9);

/**
 * Detects delimiters from the ISA segment (standard X12)
 * ISA is fixed length 106 characters.
 */
function detectDelimiters(raw: string) {
  if (!raw.startsWith('ISA')) {
    return {
      elementSeparator: '*',
      componentSeparator: ':',
      segmentTerminator: '~',
      repetitionSeparator: '^'
    };
  }

  // ISA is always 106 chars in valid X12
  const elementSeparator = raw.charAt(3);
  const componentSeparator = raw.charAt(104);
  const segmentTerminator = raw.charAt(105);

  // ISA11 is typically the repetition separator in 5010
  const parts = raw.split(elementSeparator);
  const repetitionSeparator = parts[11] && parts[11].length === 1 ? parts[11] : undefined;

  return {
    elementSeparator,
    componentSeparator,
    segmentTerminator,
    repetitionSeparator
  };
}

export const parseEdi = (rawEdi: string): EdiDocument => {
  const cleanEdi = rawEdi.trim();
  const delimiters = detectDelimiters(cleanEdi);

  // Robust split handling both with and without newlines
  const rawSegments = cleanEdi.split(delimiters.segmentTerminator)
    .map(s => s.replace(/[\n\r]/g, '').trim())
    .filter(s => s.length > 0);

  let transactionType: any = 'Unknown';

  const segments: EdiSegment[] = rawSegments.map((rawSeg, index) => {
    const elementsRaw = rawSeg.split(delimiters.elementSeparator);
    const tag = elementsRaw[0];

    if (tag === 'ST') {
        const typeCode = elementsRaw[1];
        if (['270', '271', '276', '277', '278', '837', '834', '835', '820', '850', '810', '856'].includes(typeCode)) {
            transactionType = typeCode as any;
        }
    }

    const elements = elementsRaw.slice(1).map((val, i) => {
      const repeats = (delimiters.repetitionSeparator && val.includes(delimiters.repetitionSeparator))
        ? val.split(delimiters.repetitionSeparator)
        : undefined;

      const components = val.includes(delimiters.componentSeparator) 
        ? val.split(delimiters.componentSeparator) 
        : undefined;

      return { index: i + 1, value: val, components, repeats };
    });

    return {
      id: uuid(),
      tag,
      raw: rawSeg + delimiters.segmentTerminator,
      elements,
      lineNumber: index + 1,
      depth: 0,
      children: []
    };
  });

  // Organise into tree based on HL or generic nesting
  const hlMap = new Map<string, EdiSegment>();
  segments.forEach(seg => {
    if (seg.tag === 'HL') {
      const hlId = seg.elements[0]?.value;
      if (hlId) {
        seg.hlId = hlId;
        seg.parentId = seg.elements[1]?.value || undefined;
        seg.levelCode = seg.elements[2]?.value;
        hlMap.set(hlId, seg);
      }
    }
  });

  const tree: EdiSegment[] = [];
  let currentHl: EdiSegment | null = null;

  segments.forEach(seg => {
    if (seg.tag === 'HL') {
      seg.children = [];
      currentHl = seg;
      if (seg.parentId && hlMap.has(seg.parentId)) {
        const parent = hlMap.get(seg.parentId)!;
        parent.children!.push(seg);
        seg.depth = parent.depth + 1;
      } else {
        tree.push(seg);
      }
    } else {
      if (!currentHl) tree.push(seg);
      else {
        currentHl.children!.push(seg);
        seg.depth = currentHl.depth + 1;
      }
    }
  });

  return {
    segments: hlMap.size > 0 ? tree : segments,
    ...delimiters,
    raw: rawEdi,
    transactionType
  };
};

export const flattenTree = (segments: EdiSegment[]): EdiSegment[] => {
  let flat: EdiSegment[] = [];
  segments.forEach(seg => {
    flat.push(seg);
    if (seg.children && seg.children.length > 0) {
      flat = flat.concat(flattenTree(seg.children));
    }
  });
  return flat;
};

export const getRecordRaw = (doc: EdiDocument, recordId: string): string => {
    const flat = flattenTree(doc.segments);
    const anchorIdx = flat.findIndex(s => s.id === recordId);
    if (anchorIdx === -1) return "";
    const anchorSeg = flat[anchorIdx];
    let endIdx = anchorIdx + 1;

    const isStartOfNextRecord = (seg: EdiSegment) => {
        if (['SE', 'GE', 'IEA'].includes(seg.tag)) return true;
        if (anchorSeg.tag === 'INS') return seg.tag === 'INS';
        if (anchorSeg.tag === 'CLM') return seg.tag === 'CLM';
        if (anchorSeg.tag === 'CLP') return seg.tag === 'CLP';
        if (anchorSeg.tag === 'HL' && seg.tag === 'HL') return seg.depth <= anchorSeg.depth;
        return false;
    };

    while(endIdx < flat.length && !isStartOfNextRecord(flat[endIdx])) endIdx++;
    return flat.slice(anchorIdx, endIdx).map(s => s.raw).join('');
};

export const replaceRecordInEdi = (doc: EdiDocument, newEdi: string, recordId: string): string => {
    const originalFlat = flattenTree(doc.segments);
    const anchorIdx = originalFlat.findIndex(s => s.id === recordId);
    if (anchorIdx === -1) return doc.raw; 

    const anchorSeg = originalFlat[anchorIdx];
    let endIdx = anchorIdx + 1;
    const isNext = (seg: EdiSegment) => (['SE', 'GE', 'IEA'].includes(seg.tag)) || (anchorSeg.tag === 'INS' && seg.tag === 'INS') || (anchorSeg.tag === 'CLM' && seg.tag === 'CLM') || (anchorSeg.tag === 'HL' && seg.tag === 'HL' && seg.depth <= anchorSeg.depth);
    while(endIdx < originalFlat.length && !isNext(originalFlat[endIdx])) endIdx++;

    const prefix = originalFlat.slice(0, anchorIdx).map(s => s.raw).join('');
    const suffix = originalFlat.slice(endIdx).map(s => s.raw).join('');
    return prefix + newEdi + suffix;
};

export const reindexEdi = (doc: EdiDocument): string => {
    const flat = flattenTree(doc.segments);
    let hlCounter = 0;
    const hlMap = new Map<string, string>(); 
    const reindexed = flat.map(seg => {
        if (seg.tag === 'HL') {
            hlCounter++;
            const oldId = seg.elements[0]?.value;
            const newId = hlCounter.toString();
            if (oldId) hlMap.set(oldId, newId);
            const els = [...seg.elements];
            if (els[0]) els[0] = { ...els[0], value: newId };
            return { ...seg, elements: els };
        }
        return seg;
    }).map(seg => {
        if (seg.tag === 'HL') {
            const els = [...seg.elements];
            const pId = els[1]?.value;
            if (pId && hlMap.has(pId)) els[1] = { ...els[1], value: hlMap.get(pId)! };
            const content = els.map(e => e.value).join(doc.elementSeparator);
            return { ...seg, elements: els, raw: `HL${doc.elementSeparator}${content}${doc.segmentTerminator}` };
        }
        return seg;
    });
    return reindexed.map(s => s.raw).join('');
};

export const duplicateRecordInEdi = (doc: EdiDocument, recordId: string): string => {
    const flat = flattenTree(doc.segments);
    const anchorIdx = flat.findIndex(s => s.id === recordId);
    if (anchorIdx === -1) return doc.raw;
    const raw = getRecordRaw(doc, recordId);
    const endIdx = anchorIdx + (raw.split(doc.segmentTerminator).filter(Boolean).length);
    const prefix = flat.slice(0, endIdx).map(s => s.raw).join('');
    const suffix = flat.slice(endIdx).map(s => s.raw).join('');
    return reindexEdi(parseEdi(prefix + raw + suffix));
};

export const removeRecordFromEdi = (doc: EdiDocument, recordId: string): string => {
    const flat = flattenTree(doc.segments);
    const anchorIdx = flat.findIndex(s => s.id === recordId);
    if (anchorIdx === -1) return doc.raw;
    const raw = getRecordRaw(doc, recordId);
    const segCount = raw.split(doc.segmentTerminator).filter(Boolean).length;
    const prefix = flat.slice(0, anchorIdx).map(s => s.raw).join('');
    const suffix = flat.slice(anchorIdx + segCount).map(s => s.raw).join('');
    return reindexEdi(parseEdi(prefix + suffix));
};

import { EdiDocument, EdiSegment } from '../types';
import { flattenTree } from './ediParser';
import { 
    FormData270, FormData276, FormData837, FormData834, 
    ServiceLine837, Member834, FormData850, FormData810, 
    OrderLineItem, FormData856, ShipNoticeLineItem, FormData278, FormData820, Remittance820
} from './ediBuilder';

const formatDate = (dateStr: string | undefined): string => {
    if (!dateStr || dateStr.length < 8) return dateStr || '';
    return `${dateStr.substring(0,4)}-${dateStr.substring(4,6)}-${dateStr.substring(6,8)}`;
};

const findBackwards = (segments: EdiSegment[], startIndex: number, predicate: (s: EdiSegment) => boolean): EdiSegment | undefined => {
    for (let i = startIndex; i >= 0; i--) {
        if (predicate(segments[i])) return segments[i];
    }
    return undefined;
};

export const mapEdiToForm = (doc: EdiDocument, recordId?: string): Partial<FormData270> => {
    const flat = flattenTree(doc.segments);
    const data: Partial<FormData270> = { serviceTypeCodes: [] };
    let anchorIdx = recordId ? flat.findIndex(s => s.id === recordId) : 0;
    if (anchorIdx === -1) anchorIdx = 0;

    const payerSeg = findBackwards(flat, anchorIdx, s => s.tag === 'NM1' && s.elements[0]?.value === 'PR');
    if (payerSeg) { data.payerName = payerSeg.elements[2]?.value; data.payerId = payerSeg.elements[8]?.value; }

    const provSeg = findBackwards(flat, anchorIdx, s => s.tag === 'NM1' && s.elements[0]?.value === '1P');
    if (provSeg) { data.providerName = provSeg.elements[2]?.value; data.providerNpi = provSeg.elements[8]?.value; }

    const anchorSeg = flat[anchorIdx];
    let subscriberSeg = anchorSeg;
    let dependentSeg = null;

    if (anchorSeg?.tag === 'HL') {
        const level = anchorSeg.elements[2]?.value;
        if (level === '23') {
            const pId = anchorSeg.elements[1]?.value;
            const parent = flat.find(s => s.tag === 'HL' && s.elements[0]?.value === pId);
            if (parent) subscriberSeg = flat.slice(flat.indexOf(parent)).find(s => s.tag === 'NM1' && s.elements[0]?.value === 'IL')!;
            dependentSeg = flat.slice(anchorIdx).find(s => s.tag === 'NM1' && s.elements[0]?.value === '03');
            data.hasDependent = true;
        } else {
            subscriberSeg = flat.slice(anchorIdx).find(s => s.tag === 'NM1' && s.elements[0]?.value === 'IL')!;
            data.hasDependent = false;
        }
    }

    if (subscriberSeg) {
        data.subscriberLastName = subscriberSeg.elements[2]?.value;
        data.subscriberFirstName = subscriberSeg.elements[3]?.value;
        data.subscriberId = subscriberSeg.elements[8]?.value;
        const dmg = flat.slice(flat.indexOf(subscriberSeg), flat.indexOf(subscriberSeg) + 5).find(s => s.tag === 'DMG');
        if (dmg) data.subscriberDob = formatDate(dmg.elements[1]?.value);
    }

    if (dependentSeg) {
        data.dependentLastName = dependentSeg.elements[2]?.value;
        data.dependentFirstName = dependentSeg.elements[3]?.value;
        const dmg = flat.slice(flat.indexOf(dependentSeg), flat.indexOf(dependentSeg) + 5).find(s => s.tag === 'DMG');
        if (dmg) { data.dependentDob = formatDate(dmg.elements[1]?.value); data.dependentGender = dmg.elements[2]?.value; }
    }

    const start = dependentSeg ? flat.indexOf(dependentSeg) : (subscriberSeg ? flat.indexOf(subscriberSeg) : 0);
    const dtp = flat.slice(start).find(s => s.tag === 'DTP' && (s.elements[0]?.value === '291' || s.elements[0]?.value === '472'));
    if (dtp) data.serviceDate = formatDate(dtp.elements[2]?.value);
    const eqs = flat.slice(start).filter(s => s.tag === 'EQ');
    if (eqs.length > 0) data.serviceTypeCodes = eqs.map(e => e.elements[0]?.value).filter(Boolean);

    return data;
};

export const mapEdiToForm834 = (doc: EdiDocument, recordId?: string): Partial<FormData834> => {
    const flat = flattenTree(doc.segments);
    const data: Partial<FormData834> = { 
        subscriber: { id: '', firstName: '', lastName: '', ssn: '', dob: '', gender: '', relationship: '18' },
        dependents: [] 
    };

    const sponsor = flat.find(s => s.tag === 'N1' && s.elements[0]?.value === 'P5');
    if (sponsor) { data.sponsorName = sponsor.elements[1]?.value; data.sponsorTaxId = sponsor.elements[3]?.value; }
    const payer = flat.find(s => s.tag === 'N1' && s.elements[0]?.value === 'IN');
    if (payer) { data.payerName = payer.elements[1]?.value; data.payerId = payer.elements[3]?.value; }

    let targetIdx = recordId ? flat.findIndex(s => s.id === recordId) : -1;
    if (targetIdx !== -1) {
        const ins = findBackwards(flat, targetIdx, s => s.tag === 'INS');
        if (ins) targetIdx = flat.indexOf(ins);
    } else {
        targetIdx = flat.findIndex(s => s.tag === 'INS');
    }

    if (targetIdx === -1) return data;

    // If selected is dependent, backtrack to subscriber
    if (flat[targetIdx].elements[0]?.value === 'N') {
        const sub = findBackwards(flat, targetIdx, s => s.tag === 'INS' && s.elements[0]?.value === 'Y');
        if (sub) targetIdx = flat.indexOf(sub);
    }

    const mapMember = (idx: number): Member834 => {
        const m: Member834 = { id: '', firstName: '', lastName: '', ssn: '', dob: '', gender: '', relationship: flat[idx].elements[1]?.value };
        for (let i = idx + 1; i < flat.length && flat[i].tag !== 'INS' && flat[i].tag !== 'SE'; i++) {
            const s = flat[i];
            if (s.tag === 'REF' && s.elements[0]?.value === '0F') m.id = s.elements[1]?.value;
            if (s.tag === 'REF' && s.elements[0]?.value === 'SY') m.ssn = s.elements[1]?.value;
            if (s.tag === 'NM1' && s.elements[0]?.value === 'IL') { m.lastName = s.elements[2]?.value; m.firstName = s.elements[3]?.value; }
            if (s.tag === 'DMG') { m.dob = formatDate(s.elements[1]?.value); m.gender = s.elements[2]?.value; }
            if (idx === targetIdx) {
                if (s.tag === 'REF' && s.elements[0]?.value === '1L') data.policyNumber = s.elements[1]?.value;
                if (s.tag === 'HD') { data.benefitStatus = s.elements[0]?.value; data.coverageLevelCode = s.elements[4]?.value; }
                if (s.tag === 'DTP' && s.elements[0]?.value === '348') data.planEffectiveDate = formatDate(s.elements[2]?.value);
            }
        }
        return m;
    };

    data.subscriber = mapMember(targetIdx);
    data.maintenanceType = flat[targetIdx].elements[2]?.value;
    data.maintenanceReason = flat[targetIdx].elements[3]?.value;

    for (let i = targetIdx + 1; i < flat.length && flat[i].tag !== 'SE'; i++) {
        if (flat[i].tag === 'INS') {
            if (flat[i].elements[0]?.value === 'Y') break;
            data.dependents!.push(mapMember(i));
        }
    }
    return data;
};

export const mapEdiToForm837 = (doc: EdiDocument, recordId?: string): Partial<FormData837> => {
    const flat = flattenTree(doc.segments);
    const data: Partial<FormData837> = { serviceLines: [] };
    let anchorIdx = recordId ? flat.findIndex(s => s.id === recordId) : 0;
    if (anchorIdx === -1) anchorIdx = 0;

    const receiver = flat.find(s => s.tag === 'NM1' && s.elements[0]?.value === '40');
    if (receiver) { data.payerName = receiver.elements[2]?.value; data.payerId = receiver.elements[8]?.value; }

    const billProv = flat.find(s => s.tag === 'NM1' && s.elements[0]?.value === '85');
    if (billProv) {
        data.billingProviderName = billProv.elements[2]?.value;
        data.billingProviderNpi = billProv.elements[8]?.value;
        const bpIdx = flat.indexOf(billProv);
        const n3 = flat[bpIdx + 1]?.tag === 'N3' ? flat[bpIdx + 1] : null;
        const n4 = flat[bpIdx + 2]?.tag === 'N4' ? flat[bpIdx + 2] : null;
        if (n3) data.billingProviderAddress = n3.elements[0]?.value;
        if (n4) { data.billingProviderCity = n4.elements[0]?.value; data.billingProviderState = n4.elements[1]?.value; data.billingProviderZip = n4.elements[2]?.value; }
        const refEi = flat.slice(bpIdx, bpIdx + 5).find(s => s.tag === 'REF' && s.elements[0]?.value === 'EI');
        if (refEi) data.billingTaxId = refEi.elements[1]?.value;
    }

    const subSeg = findBackwards(flat, anchorIdx, s => s.tag === 'NM1' && s.elements[0]?.value === 'IL');
    if (subSeg) {
        data.subscriberLastName = subSeg.elements[2]?.value;
        data.subscriberFirstName = subSeg.elements[3]?.value;
        data.subscriberId = subSeg.elements[8]?.value;
        const dmg = flat.slice(flat.indexOf(subSeg), flat.indexOf(subSeg) + 5).find(s => s.tag === 'DMG');
        if (dmg) { data.subscriberDob = formatDate(dmg.elements[1]?.value); data.subscriberGender = dmg.elements[2]?.value; }
    }

    let clmSeg = flat[anchorIdx]?.tag === 'CLM' ? flat[anchorIdx] : findBackwards(flat, anchorIdx, s => s.tag === 'CLM');
    if (clmSeg) {
        data.claimId = clmSeg.elements[0]?.value;
        data.totalCharge = clmSeg.elements[1]?.value;
        const clm05 = clmSeg.elements[4]?.value || '';
        if (clm05.split(':')[0]?.length === 3) { data.type = 'Institutional'; data.typeOfBill = clm05.split(':')[0]; }
        else { data.type = 'Professional'; data.placeOfService = clm05.split(':')[0]; }

        const idx = flat.indexOf(clmSeg);
        const hi = flat.slice(idx, idx + 10).find(s => s.tag === 'HI');
        if (hi) {
            data.diagnosisCode1 = hi.elements[0]?.value?.split(':')[1] || hi.elements[0]?.value;
            data.diagnosisCode2 = hi.elements[1]?.value?.split(':')[1] || hi.elements[1]?.value;
        }

        for (let i = idx + 1; i < flat.length && flat[i].tag !== 'CLM' && flat[i].tag !== 'SE'; i++) {
            const s = flat[i];
            if (['SV1', 'SV2', 'SV3'].includes(s.tag)) {
                const line: ServiceLine837 = { procedureCode: '', lineCharge: '', units: '', serviceDate: '' };
                if (s.tag === 'SV1') { line.procedureCode = s.elements[0]?.value?.split(':')[1] || s.elements[0]?.value; line.lineCharge = s.elements[1]?.value; line.units = s.elements[3]?.value; }
                else if (s.tag === 'SV2') { line.procedureCode = s.elements[1]?.value?.split(':')[1] || s.elements[1]?.value; line.lineCharge = s.elements[2]?.value; line.units = s.elements[4]?.value; }
                else { line.procedureCode = s.elements[0]?.value?.split(':')[1] || s.elements[0]?.value; line.lineCharge = s.elements[1]?.value; line.units = s.elements[5]?.value; data.type = 'Dental'; }
                const dtp = flat[i+1]?.tag === 'DTP' ? flat[i+1] : null;
                if (dtp && dtp.elements[0]?.value === '472') line.serviceDate = formatDate(dtp.elements[2]?.value);
                data.serviceLines!.push(line);
            }
        }
    }
    return data;
};

