          const newLines = [...formData856.lines];
          newLines[idx] = { ...newLines[idx], [field]: value };
          onChange856({ ...formData856, lines: newLines });
      }
  };

  const renderForm856 = () => {
      if (!formData856 || !onChange856) return null;
