  const handleFormChange = (newData: FormData270) => {
    setFormData(newData);
    const newEdi = build270(newData);
    const updated = replaceRecordInEdi(doc!, newEdi, selectedRecordId!);
    setRawEdi(updated);
    processEdi(updated, false);
