  const handleForm276Change = (newData: FormData276) => {
    setFormData276(newData);
    const newEdi = build276(newData);
    const updated = replaceRecordInEdi(doc!, newEdi, selectedRecordId!);
    setRawEdi(updated);
    processEdi(updated, false);
  };

